const n=JSON.parse('{"key":"v-9f935a06","path":"/storehouse/Love%20brain.html","title":"语录","lang":"zh-CN","frontmatter":{"title":"语录","icon":"fab fa-markdown","category":["情感"],"tag":["科普"],"prev":null},"headers":[{"level":2,"title":"感情","slug":"感情","link":"#感情","children":[]},{"level":2,"title":"商业","slug":"商业","link":"#商业","children":[]}],"git":{"createdTime":null,"updatedTime":null,"contributors":[]},"readingTime":{"minutes":1.55,"words":466},"filePathRelative":"storehouse/Love brain.md","excerpt":"<h2> 感情</h2>\\n<ul>\\n<li>\\n<p>因为有你在，所以我才敢放肆的去做正义的事情，不怕被坏人欺负，因为你会为我撑腰。</p>\\n</li>\\n<li>\\n<p>人事间的事情莫过于此，用一个瞬间来喜欢一样东西，用余生来慢慢拷问自己。</p>\\n</li>\\n<li>\\n<p>当主角多累啊，闪闪发光的，还得保证每个人都能看到，你不一定非要成为太阳，想做个星星，萤火虫，路灯都行，想发光的时候就发光，哪怕你永远都不发光，有的人还是一眼就看到你了。</p>\\n</li>\\n<li>\\n<p>到了一个陌生的地方，就要慢慢的填满自己的东西，这样才会有归属感。</p>\\n</li>\\n<li>\\n<p>在我活着的人生里，仅仅只是为了活着，梦想真是一个好东西，他让我觉得不只活着。</p>\\n</li>\\n<li>\\n<p>生命的烙印不会因为你的瞎想而发生一点点的改变。</p>\\n</li>\\n<li>\\n<p>尽量让自己开心一点，但也别把明天的路堵死。</p>\\n</li>\\n<li>\\n<p>不要困于别人的期待，徒耗自己的精力。</p>\\n</li>\\n<li>\\n<p>不要让自己有负罪感，因为负罪感会抢走灵魂。</p>\\n</li>\\n<li>\\n<p>无论如何你走的路都会被人说三到四，做也会被人说，不做也会被人说，那就在自己想做的情况下做吧。</p>\\n</li>\\n</ul>"}');export{n as data};
